          height: var(--input-height);
          max-width: 100%;
          min-width: 0;
          font-family: var(--font-sans, 'Inter', sans-serif);
        }

        /* The glowing/animated layers behind everything */
        .retro-white,
        .retro-border,
        .retro-darkBorderBg,
        .retro-glow {
          max-height: 100%;
          max-width: 100%;
          height: 100%;
          width: 100%;
          position: absolute;
          overflow: hidden;
          z-index: 0; /* Base layer */
          border-radius: 8px;
          filter: blur(3px);
          top: 0;
          left: 0;
        }

        /* The solid background that sits on top of glow but behind text */
        .retro-inner-bg {
          position: absolute;
          inset: 1px; /* Leave 1px gap for the glowing border to show */
          background-color: #f8fafc; /* slate-50 */
          border-radius: 7px; /* Slightly smaller radius */
