const PayloadModal: React.FC<{
    isOpen: boolean;
    onClose: () => void;
    onSave: (payload: Partial<Payload>) => Promise<void>;
    payload?: Payload | null;
}> = ({ isOpen, onClose, onSave, payload }) => {
    const [title, setTitle] = useState('');
    const [category, setCategory] = useState('');
    const [code, setCode] = useState('');
    const [description, setDescription] = useState('');
    const [isVisible, setIsVisible] = useState(true);
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (payload) {
            setTitle(payload.title);
            setCategory(payload.category);
            setCode(payload.code);
            setDescription(payload.description || '');
            setIsVisible(payload.is_visible);
        } else {
            setTitle('');
            setCategory('XSS');
            setCode('');
            setDescription('');
            setIsVisible(true);
        }
    }, [payload, isOpen]);

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        await onSave({
            id: payload?.id,
            title,
            category,
            code,
            description,
            is_visible: isVisible
        });
        setIsSaving(false);
        onClose();
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in">
            {/* Modal Container: Maximized width for code editing */}
            <div className="bg-slate-900 border border-slate-700 w-full max-w-4xl rounded-xl shadow-2xl flex flex-col overflow-hidden animate-slide-up max-h-[95vh]">
                <header className="p-5 border-b border-slate-800 bg-slate-900/50 flex justify-between items-center flex-shrink-0">
                    <h3 className="text-lg font-bold text-white">{payload ? 'Edit Payload' : 'New Payload'}</h3>
                    <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors p-2"><span className="text-2xl leading-none">&times;</span></button>
                </header>

                <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto flex-1">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                        <div>
                            <label className="block text-xs font-bold text-slate-400 uppercase mb-1.5">Title</label>
                            <input value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-slate-800 border border-slate-700 rounded-lg p-2.5 text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none" placeholder="e.g. Basic Alert" required />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-slate-400 uppercase mb-1.5">Category</label>
                            <input value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-800 border border-slate-700 rounded-lg p-2.5 text-white focus:ring-2 focus:ring-indigo-500 outline-none" list="categories" placeholder="Type or select..." required />
                            <datalist id="categories">
                                <option value="XSS" />
                                <option value="HTML Injection" />
                                <option value="SQLi" />
                                <option value="LFI" />
                                <option value="RCE" />
                                <option value="SSTI" />
                            </datalist>
                        </div>
                    </div>

                    <div className="flex flex-col flex-1 h-full min-h-[300px]">
                        <label className="block text-xs font-bold text-slate-400 uppercase mb-1.5">Payload Code (Unlimited)</label>
                        <textarea 
                            value={code} 
                            onChange={e => setCode(e.target.value)} 
                            className="w-full flex-1 bg-slate-950 border border-slate-800 rounded-lg p-4 text-green-400 font-mono text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-y min-h-[300px]" 
                            placeholder="Enter your payload code here..." 
                            spellCheck={false}
                            required 
                        />
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-slate-400 uppercase mb-1.5">Description (Optional)</label>
                        <textarea value={description} onChange={e => setDescription(e.target.value)} className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-slate-300 text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-y" rows={3} placeholder="Brief explanation..." />
                    </div>

                    <div className="flex items-center gap-2 cursor-pointer p-1">
                        <input type="checkbox" id="visible-check" checked={isVisible} onChange={e => setIsVisible(e.target.checked)} className="rounded bg-slate-800 border-slate-600 text-indigo-500 focus:ring-indigo-500 w-4 h-4" />
                        <label htmlFor="visible-check" className="text-sm font-medium text-slate-300 cursor-pointer">Visible to all users</label>
                    </div>
                </form>

                <footer className="p-5 border-t border-slate-800 bg-slate-900/50 flex justify-end gap-3 flex-shrink-0">
                    <button type="button" onClick={onClose} className="px-5 py-2.5 text-sm font-semibold text-slate-300 hover:text-white bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors">Cancel</button>
                    <button onClick={handleSubmit} disabled={isSaving} className="px-6 py-2.5 text-sm font-bold text-white bg-indigo-600 hover:bg-indigo-500 rounded-lg shadow-lg shadow-indigo-500/20 transition-all flex items-center gap-2">
                        {isSaving ? <SpinnerIcon className="w-4 h-4 animate-spin"/> : 'Save Payload'}
                    </button>
                </footer>
            </div>
        </div>
    );
};

const ResourcesPage: React.FC<{ user?: User }> = ({ user }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [activePayloadCategory, setActivePayloadCategory] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [payloads, setPayloads] = useState<Payload[]>([]);
  const [isLoadingPayloads, setIsLoadingPayloads] = useState(false);

  // Admin State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPayload, setEditingPayload] = useState<Payload | null>(null);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  const { addNotification } = useNotificationState();
  const isAdmin = user?.role === 'admin';

  const categories = ['All', 'Learning', 'Tools', 'Reference', 'Premium Payloads'];

  // Handle category change or search input
  const handleCategoryChange = (category: string) => {
      setSelectedCategory(category);
      setSearchQuery('');
      setActivePayloadCategory(null); // Reset deep navigation
  };

  const handleSearchChange = (val: string) => {
      setSearchQuery(val);
      if (val) {
          setActivePayloadCategory(null); // Reset folder view on search
      }
  };

  // Initial Fetch & Realtime Subscription
  useEffect(() => {
      const fetchPayloads = async () => {
          setIsLoadingPayloads(true);
          try {
              const data = await getPayloads(isAdmin);
              setPayloads(data);
          } catch (error) {
              console.error("Failed to load payloads", error);
          } finally {
              setIsLoadingPayloads(false);
          }
      };

      if (selectedCategory === 'Premium Payloads') {
          fetchPayloads();

          const supabase = getSupabase();
          if (supabase) {
              const channel = supabase.channel('public:payloads')
                  .on('postgres_changes', { event: '*', schema: 'public', table: 'payloads' }, (payload) => {
                      if (payload.eventType === 'INSERT') {
                          if (isAdmin || (payload.new as Payload).is_visible) {
                              setPayloads(prev => [payload.new as Payload, ...prev]);
                          }
                      } else if (payload.eventType === 'UPDATE') {
                          setPayloads(prev => {
                              const updated = payload.new as Payload;
                              if (!isAdmin && !updated.is_visible) {
                                  return prev.filter(p => p.id !== updated.id);
                              }
                              return prev.map(p => p.id === updated.id ? updated : p);
                          });
                      } else if (payload.eventType === 'DELETE') {
                          setPayloads(prev => prev.filter(p => p.id !== payload.old.id));
                      }
                  })
                  .subscribe();
              return () => { supabase.removeChannel(channel); };
          }
      }
  }, [selectedCategory, isAdmin]);

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    addNotification({ title: 'Copied', message: 'Payload copied to clipboard.', type: 'success', duration: 2000, showToast: true });
    setTimeout(() => setCopiedId(null), 2000);
  };

  const handleSavePayload = async (data: Partial<Payload>) => {
      try {
          await savePayload(data);
          addNotification({ title: 'Success', message: data.id ? 'Payload updated.' : 'Payload created.', type: 'success' });
      } catch (error) {
          addNotification({ title: 'Error', message: 'Failed to save payload.', type: 'error' });
      }
  };

  const handleToggleVisibility = async (payload: Payload) => {
      if (!isAdmin) return;
      try {
          await savePayload({ id: payload.id, is_visible: !payload.is_visible });
      } catch (error) {
          addNotification({ title: 'Error', message: 'Could not update visibility.', type: 'error' });
      }
  };

  const handleDeletePayload = async () => {
      if (!deleteId) return;
      try {
          await deletePayload(deleteId);
          addNotification({ title: 'Deleted', message: 'Payload removed.', type: 'success' });
          setDeleteId(null);
      } catch (error) {
          addNotification({ title: 'Error', message: 'Could not delete payload.', type: 'error' });
      }
  };

  const filteredResources = resourcesData.filter(resource => {
    const matchesSearch = resource.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                          resource.description.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || resource.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const filteredPayloads = payloads.filter(payload => {
      const query = searchQuery.toLowerCase();
      // If we are deep in a category AND NOT SEARCHING, filter by exact category
      if (activePayloadCategory && !query) {
          return payload.category === activePayloadCategory;
      }
      // Otherwise filter by search query across all fields
      return payload.title.toLowerCase().includes(query) || 
             (payload.description || '').toLowerCase().includes(query) || 
             payload.code.toLowerCase().includes(query) ||
             payload.category.toLowerCase().includes(query);
  });

  // Calculate payload categories for folders
  const payloadCategories = useMemo(() => {
      const cats: Record<string, number> = {};
      payloads.forEach(p => {
          cats[p.category] = (cats[p.category] || 0) + 1;
      });
      return Object.entries(cats).map(([name, count]) => ({ name, count }));
  }, [payloads]);

  const showFolders = selectedCategory === 'Premium Payloads' && !activePayloadCategory && !searchQuery;

  return (
    <div className="h-full w-full flex flex-col bg-slate-50 dark:bg-slate-900 overflow-hidden relative">
      <PayloadModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingPayload(null); }} 
        onSave={handleSavePayload}
        payload={editingPayload}
      />

      <ConfirmationModal
        isOpen={!!deleteId}
        onClose={() => setDeleteId(null)}
        onConfirm={handleDeletePayload}
        title="Delete Payload"
        confirmText="Delete"
        confirmButtonClass="bg-red-600 hover:bg-red-700"
      >
        <p>Are you sure you want to permanently delete this payload?</p>
      </ConfirmationModal>

      {/* Header */}
      <header className="p-6 border-b border-slate-200 dark:border-slate-800 flex-shrink-0 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md sticky top-0 z-10">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 max-w-7xl mx-auto">
          <div>
            <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Resources</h1>
            <p className="text-sm text-slate-500 dark:text-slate-400">Curated tools, links, and premium payloads.</p>
          </div>

          <div className="flex items-center gap-3 w-full md:w-auto">
            <div className="w-full md:w-72">
                <RetroSearchInput 
                value={searchQuery} 
                onChange={handleSearchChange} 
                placeholder={selectedCategory === 'Premium Payloads' ? "Search payloads..." : "Find resources..."}
                width="100%"
                />
            </div>
            {isAdmin && selectedCategory === 'Premium Payloads' && (
                <button 
                    onClick={() => { setEditingPayload(null); setIsModalOpen(true); }}
                    className="p-2 bg-indigo-600 text-white rounded-lg shadow-lg hover:bg-indigo-500 transition-colors flex-shrink-0"
                    title="Add Payload"
                >
                    <PlusIcon className="w-6 h-6" />
                </button>
            )}
          </div>
        </div>

        {/* Category Tabs */}
        <div className="flex gap-2 mt-6 overflow-x-auto hide
